// Email Classification Domain Types with Branded Types
export namespace EmailClassification {
  // Branded types for domain-specific validation
  export type EmailId = string & { readonly _brand: 'EmailId' };
  export type CategoryName = string & { readonly _brand: 'CategoryName' };
  export type ConfidenceScore = number & { readonly _brand: 'ConfidenceScore' };
  export type ProcessingTimeMs = number & { readonly _brand: 'ProcessingTimeMs' };

  // Type guards for branded types
  export const EmailId = {
    create: (value: string): EmailId | null => {
      return /^[a-zA-Z0-9-]+$/.test(value) ? value as EmailId : null;
    },
    is: (value: unknown): value is EmailId => {
      return typeof value === 'string' && /^[a-zA-Z0-9-]+$/.test(value);
    }
  };

  export const ConfidenceScore = {
    create: (value: number): ConfidenceScore | null => {
      return value >= 0 && value <= 1 ? value as ConfidenceScore : null;
    },
    is: (value: unknown): value is ConfidenceScore => {
      return typeof value === 'number' && value >= 0 && value <= 1;
    }
  };

  // Discriminated union for classification results
  export type ClassificationResult =
    | {
        readonly status: 'success';
        readonly emailId: EmailId;
        readonly categories: ReadonlyArray<Category>;
        readonly processingTime: ProcessingTimeMs;
        readonly explainabilityTrace: ExplainabilityTrace;
      }
    | {
        readonly status: 'error';
        readonly emailId: EmailId;
        readonly error: ClassificationError;
        readonly processingTime: ProcessingTimeMs;
      }
    | {
        readonly status: 'pending';
        readonly emailId: EmailId;
        readonly estimatedCompletion: Date;
      };

  // Advanced generic for classification pipeline stages
  export interface ClassificationStage<TInput, TOutput, TContext = unknown> {
    readonly name: string;
    readonly execute: (
      input: TInput,
      context: TContext
    ) => Promise<StageResult<TOutput>>;
    readonly validate: (input: TInput) => input is TInput;
  }

  // Conditional type for stage result
  export type StageResult<T> = T extends never
    ? { readonly status: 'skipped' }
    : {
        readonly status: 'completed';
        readonly output: T;
        readonly metadata: StageMetadata;
      };

  // Recursive type for nested category hierarchies
  export interface CategoryHierarchy<T extends string = string> {
    readonly name: T;
    readonly confidence: ConfidenceScore;
    readonly children?: ReadonlyArray<CategoryHierarchy<T>>;
    readonly metadata: CategoryMetadata;
  }

  // Template literal types for type-safe event names
  export type EmailEventType =
    | `email.${string}.received`
    | `email.${string}.classified`
    | `email.${string}.error`;

  // Mapped type for event payloads
  export type EmailEventPayload<T extends EmailEventType> =
    T extends `email.${infer U}.received`
      ? { emailId: EmailId; content: string; receivedAt: Date }
    : T extends `email.${infer U}.classified`
      ? { emailId: EmailId; result: ClassificationResult }
    : T extends `email.${infer U}.error`
      ? { emailId: EmailId; error: ClassificationError }
    : never;

  // Type-safe event emitter
  export interface EmailEventEmitter {
    emit<T extends EmailEventType>(
      event: T,
      payload: EmailEventPayload<T>
    ): void;
    on<T extends EmailEventType>(
      event: T,
      handler: (payload: EmailEventPayload<T>) => void
    ): void;
  }
}

