### Type-Safe State Management
```typescript
// Advanced state machine with type safety
export namespace EmailProcessingStateMachine {
  // State definitions with branded types
  export type State =
    | 'idle'
    | 'receiving'
    | 'classifying'
    | 'processing'
    | 'completed'
    | 'failed';

  export type Event =
    | { type: 'START_PROCESSING'; payload: { emailId: EmailId } }
    | { type: 'EMAIL_RECEIVED'; payload: { content: string } }
    | { type: 'CLASSIFICATION_COMPLETE'; payload: { result: ClassificationResult } }
    | { type: 'PROCESSING_COMPLETE'; payload: { result: ProcessingResult } }
    | { type: 'ERROR_OCCURRED'; payload: { error: ProcessingError } }
    | { type: 'RETRY'; payload: { attempt: number } }
    | { type: 'RESET'; payload?: never };

  // Type-safe state transitions
  export type StateTransitions = {
    idle: {
      START_PROCESSING: 'receiving';
    };
    receiving: {
      EMAIL_RECEIVED: 'classifying';
      ERROR_OCCURRED: 'failed';
    };
    classifying: {
      CLASSIFICATION_COMPLETE: 'processing';
      ERROR_OCCURRED: 'failed';
    };
    processing: {
      PROCESSING_COMPLETE: 'completed';
      ERROR_OCCURRED: 'failed';
    };
    completed: {
      RESET: 'idle';
    };
    failed: {
      RETRY: 'receiving';
      RESET: 'idle';
    };
  };

  // Type-safe transition function
  export type TransitionFunction<
    TCurrentState extends State,
    TEvent extends Event
  > = TEvent['type'] extends keyof StateTransitions[TCurrentState]
    ? StateTransitions[TCurrentState][TEvent['type']]
    : never;

  // State machine implementation
  export class EmailStateMachine {
    constructor(private state: State = 'idle') {}

    // Type-safe transition method
    public transition<
      TCurrentState extends State,
      TEvent extends Event
    >(
      this: { state: TCurrentState },
      event: TEvent
    ): EmailStateMachine & {
      state: TransitionFunction<TCurrentState, TEvent>;
    } {
      const transitions = stateTransitions[this.state] as any;
      const newState = transitions[event.type];

      if (!newState) {
        throw new InvalidTransitionError(this.state, event.type);
      }

      return new EmailStateMachine(newState) as any;
    }

    // Type-safe state checking
    public is<T extends State>(state: T): this is EmailStateMachine & { state: T } {
      return this.state === state;
    }

    // Exhaustive state checking
    public match<T>(
      handlers: {
        [K in State]: (machine: EmailStateMachine & { state: K }) => T;
      }
    ): T {
      return handlers[this.state](this as any);
    }
  }
}
