### Advanced Generic Programming
```typescript
// Higher-order type for pipeline composition
export type Pipeline<TSteps extends readonly unknown[]> = TSteps extends readonly [
  infer TFirst,
  ...infer TRest
]
  ? TFirst extends (input: infer TInput) => infer TOutput
    ? TRest extends readonly []
      ? (input: TInput) => TOutput
      : TRest extends readonly [(input: TOutput) => unknown, ...unknown[]]
        ? (input: TInput) => ReturnType<Pipeline<TRest>>
        : never
    : never
  : never;

// Type-safe pipeline builder
export class PipelineBuilder<TSteps extends readonly unknown[] = []> {
  constructor(private steps: TSteps) {}

  public pipe<TNext extends (input: any) => any>(
    step: TNext
  ): PipelineBuilder<[...TSteps, TNext]> {
    return new PipelineBuilder([...this.steps, step]);
  }

  public build(): Pipeline<TSteps> {
    return ((input: any) => {
      return this.steps.reduce((acc, step) => (step as any)(acc), input);
    }) as Pipeline<TSteps>;
  }
}

// Usage example with full type inference
const emailPipeline = new PipelineBuilder([])
  .pipe((email: RawEmail) => parseEmail(email))
  .pipe((parsed: ParsedEmail) => validateEmail(parsed))
  .pipe((validated: ValidatedEmail) => classifyEmail(validated))
  .pipe((classified: ClassifiedEmail) => enrichEmail(classified))
  .build();

// Type is automatically: (email: RawEmail) => EnrichedEmail
