### Type-Safe Error Handling
```typescript
// Result type for functional error handling
export type Result<T, E = Error> =
  | { readonly success: true; readonly data: T }
  | { readonly success: false; readonly error: E };

// Result utility functions
export namespace Result {
  export const ok = <T>(data: T): Result<T, never> => ({
    success: true,
    data
  });

  export const err = <E>(error: E): Result<never, E> => ({
    success: false,
    error
  });

  // Type-safe chaining
  export const chain = <T, U, E>(
    result: Result<T, E>,
    fn: (data: T) => Result<U, E>
  ): Result<U, E> => {
    return result.success ? fn(result.data) : result;
  };

  // Type-safe mapping
  export const map = <T, U, E>(
    result: Result<T, E>,
    fn: (data: T) => U
  ): Result<U, E> => {
    return result.success ? ok(fn(result.data)) : result;
  };

  // Type-safe error mapping
  export const mapError = <T, E1, E2>(
    result: Result<T, E1>,
    fn: (error: E1) => E2
  ): Result<T, E2> => {
    return result.success ? result : err(fn(result.error));
  };

  // Unwrap with default
  export const unwrapOr = <T, E>(
    result: Result<T, E>,
    defaultValue: T
  ): T => {
    return result.success ? result.data : defaultValue;
  };
}

// Type-safe async result handling
export type AsyncResult<T, E = Error> = Promise<Result<T, E>>;

export namespace AsyncResult {
  export const fromPromise = async <T>(
    promise: Promise<T>
  ): AsyncResult<T, Error> => {
    try {
      const data = await promise;
      return Result.ok(data);
    } catch (error) {
      return Result.err(error instanceof Error ? error : new Error(String(error)));
    }
  };

  export const chain = async <T, U, E>(
    asyncResult: AsyncResult<T, E>,
    fn: (data: T) => AsyncResult<U, E>
  ): AsyncResult<U, E> => {
    const result = await asyncResult;
    return result.success ? fn(result.data) : result;
  };
}
