// Build performance monitoring
export class TypeScriptBuildMonitor {
  private startTime: number = 0;
  private typeCheckTime: number = 0;
  private emitTime: number = 0;

  public startBuild(): void {
    this.startTime = performance.now();
  }

  public recordTypeCheck(): void {
    this.typeCheckTime = performance.now() - this.startTime;
  }

  public recordEmit(): void {
    this.emitTime = performance.now() - this.startTime - this.typeCheckTime;
  }

  public getBuildMetrics(): BuildMetrics {
    return {
      totalTime: performance.now() - this.startTime,
      typeCheckTime: this.typeCheckTime,
      emitTime: this.emitTime,
      timestamp: new Date().toISOString()
    };
  }
}

